<?php $base="http://172.19.0.8/api/v1"; $pass=0;$fail=0;$errors=[]; function req($m,$u,$d=null,$t=null){$ch=curl_init($u);$h=["Content-Type: application/json","Accept: application/json"];if($t)$h[]="Authorization: Bearer $t";curl_setopt_array($ch,[CURLOPT_CUSTOMREQUEST=>$m,CURLOPT_HTTPHEADER=>$h,CURLOPT_RETURNTRANSFER=>1,CURLOPT_TIMEOUT=>8]);if($d)curl_setopt($ch,CURLOPT_POSTFIELDS,json_encode($d));$b=curl_exec($ch);$c=curl_getinfo($ch,CURLINFO_HTTP_CODE);curl_close($ch);return ["code"=>$c,"body"=>json_decode($b,true),"raw"=>$b];} function t($l,$r,$e,&$p,&$f,&$er){$ok=$r["code"]===$e;echo($ok?"OK":"FAIL")." $l HTTP:".$r["code"]."\n";if($ok)$p++;else{$f++;$er[]="$l:".$r["code"].":".substr($r["raw"],0,150);}return $ok;} $r=req("POST","$base/auth/login",["email"=>"owner@demo.sa","password"=>"password"]); t("login",$r,200,$pass,$fail,$errors); $tok=$r["body"]["token"]??""; foreach(["customers","vehicles","products","invoices","quotes","work-orders","bays","bookings","ledger","wallet","governance/policies","contracts"] as $ep) t($ep,req("GET","$base/$ep",null,$tok),200,$pass,$fail,$errors); $nv=req("POST","$base/vehicles",["plate_number"=>"T".rand(100,999),"make"=>"Toyota","model"=>"Test","year"=>2023],$tok); t("create-vehicle",$nv,201,$pass,$fail,$errors); echo "SUMMARY:PASS=$pass,FAIL=$fail\n"; foreach($errors as $e) echo "ERR:$e\n"; ?>
